Prolog:
sPrefix = Trim(pPrefix);
If(sPrefix @= '');
  sPrefix = 'IMF';
EndIf;

sCreateInitialVersions = Upper(Trim(pCreateInitialVersions));
sInitialVersionId = Trim(pInitialVersionId);
sCreatedBy = Trim(pCreatedBy);

If(sCreateInitialVersions @= '');
  sCreateInitialVersions = 'Y';
EndIf;
If(sInitialVersionId @= '');
  sInitialVersionId = 'V001';
EndIf;
If(sCreatedBy @= '');
  sCreatedBy = 'DEMO';
EndIf;

ExecuteProcess(
  sPrefix | '.P.Init.Project',
  'pPrefix', sPrefix,
  'pCreateSampleConfig', 'Y'
);

nDimensionIndex = 1;
While(nDimensionIndex <= 5);
  If(nDimensionIndex = 1);
    sDimensionCode = 'Account';
  ElseIf(nDimensionIndex = 2);
    sDimensionCode = 'Organization';
  ElseIf(nDimensionIndex = 3);
    sDimensionCode = 'Product';
  ElseIf(nDimensionIndex = 4);
    sDimensionCode = 'Product Group';
  Else;
    sDimensionCode = 'Project';
  EndIf;

  ExecuteProcess(
    sPrefix | '.P.Dimension.Onboard',
    'pPrefix', sPrefix,
    'pDimensionCode', sDimensionCode,
    'pMasterDimensionName', sDimensionCode,
    'pCreatePhysicalDimension', 'Y',
    'pIsActive', 'Y'
  );

  ExecuteProcess(
    sPrefix | '.P.Demo.SeedDimension',
    'pPrefix', sPrefix,
    'pDimensionCode', sDimensionCode,
    'pCreatedBy', sCreatedBy
  );

  If(sCreateInitialVersions @= 'Y');
    ExecuteProcess(
      sPrefix | '.P.Version.Create',
      'pPrefix', sPrefix,
      'pDimensionCode', sDimensionCode,
      'pVersionId', sInitialVersionId,
      'pSourceType', 'MASTER',
      'pSourceVersion', '',
      'pCreatedBy', sCreatedBy,
      'pNotes', 'Initial demo version created by IMF.P.Demo.SetupModel.'
    );
  EndIf;

  nDimensionIndex = nDimensionIndex + 1;
End;
